import sharp from 'sharp';
import pngToIco from 'png-to-ico';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

// Portable paths (relative to this repo) -- replaces the old
// scripts/generate-assets-v2.js, which hardcoded another machine's
// absolute paths (/home/z/my-project/...) and can't be re-run by anyone
// else. This script also fixes two visual defects found in that pass:
//
// 1. The source badge is a circle inscribed in a square RGB (no alpha)
//    canvas -- every favicon/icon generated by a plain resize carried
//    visible white square corners around the circular logo. Browser
//    tabs, the Windows taskbar, and desktop PWA icons don't auto-round
//    corners (unlike iOS/Android app icons), so this showed up in the
//    worst places. Fixed by masking to the inscribed circle (radius =
//    width/2) so the corners become transparent instead of white.
//
// 2. og-share/og-image was 1200x630 with `fit: cover`, which zooms a
//    SQUARE 1:1 source until it fills a 1.9:1 frame and center-crops the
//    overflow -- slicing the top/bottom off the circular ring text.
//    Fixed by making it a proper square (1200x1200) with `fit: contain`,
//    so the full logo is always visible, never cropped.

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_DIR = path.resolve(__dirname, '..');
const PUBLIC_DIR = path.join(REPO_DIR, 'public');
const ICONS_DIR = path.join(REPO_DIR, 'icons');
const MASTER_SRC = path.join(REPO_DIR, 'src/assets/images/campaign-logo-master.png');

const BRAND_GREEN = { r: 0, g: 106, b: 78, alpha: 1 }; // #006A4E, matches theme_color

if (!fs.existsSync(MASTER_SRC)) {
  console.error(`Missing source file: ${MASTER_SRC}`);
  process.exit(1);
}

/** Mask an already-square source image to its inscribed circle (transparent corners). */
async function circularMask(size) {
  const resized = await sharp(MASTER_SRC).resize(size, size, { fit: 'cover' }).png().toBuffer();
  const circleSvg = Buffer.from(
    `<svg width="${size}" height="${size}"><circle cx="${size / 2}" cy="${size / 2}" r="${size / 2}" fill="#fff"/></svg>`
  );
  return sharp(resized).composite([{ input: circleSvg, blend: 'dest-in' }]).png().toBuffer();
}

/** Opaque brand-green tile with the logo centered in the maskable "safe zone" (inner ~80%). */
async function maskableSafeIcon(size) {
  const inner = Math.round(size * 0.72);
  const logo = await sharp(MASTER_SRC).resize(inner, inner, { fit: 'contain', background: BRAND_GREEN }).png().toBuffer();
  return sharp({ create: { width: size, height: size, channels: 4, background: BRAND_GREEN } })
    .composite([{ input: logo, gravity: 'center' }])
    .png()
    .toBuffer();
}

async function main() {
  let count = 0;
  console.log('Plantation Tracker -- Branding regeneration (circular icons + square OG)\n');

  // ---- Favicon / browser & desktop icons: circular, transparent corners ----
  for (const size of [16, 32, 48]) {
    const buf = await circularMask(size);
    await sharp(buf).toFile(path.join(PUBLIC_DIR, `favicon-${size}x${size}.png`));
    console.log(`  [${++count}] public/favicon-${size}x${size}.png (circular)`);
  }

  const icoBuffer = await pngToIco([
    path.join(PUBLIC_DIR, 'favicon-16x16.png'),
    path.join(PUBLIC_DIR, 'favicon-32x32.png'),
    path.join(PUBLIC_DIR, 'favicon-48x48.png'),
  ]);
  fs.writeFileSync(path.join(PUBLIC_DIR, 'favicon.ico'), icoBuffer);
  console.log(`  [${++count}] public/favicon.ico (real multi-size 16/32/48 stack)`);

  // logo.png -- circular, transparent (used standalone + embedded into logo.svg)
  const logo512 = await circularMask(512);
  fs.writeFileSync(path.join(PUBLIC_DIR, 'logo.png'), logo512);
  console.log(`  [${++count}] public/logo.png (512x512, circular)`);

  const logoSvg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 512 512" width="512" height="512">
  <image href="data:image/png;base64,${logo512.toString('base64')}" width="512" height="512"/>
</svg>`;
  fs.writeFileSync(path.join(PUBLIC_DIR, 'logo.svg'), logoSvg);
  console.log(`  [${++count}] public/logo.svg`);

  // apple-touch-icon.png -- intentionally OPAQUE/square (Apple HIG: iOS ignores
  // alpha and renders transparent pixels as solid black, then rounds the
  // corners itself), so this one must NOT be circular-masked.
  await sharp(MASTER_SRC).resize(180, 180, { fit: 'contain', background: { r: 255, g: 255, b: 255, alpha: 1 } }).flatten({ background: '#ffffff' }).png().toFile(path.join(PUBLIC_DIR, 'apple-touch-icon.png'));
  console.log(`  [${++count}] public/apple-touch-icon.png (180x180, opaque square -- iOS rounds it itself)`);

  // ---- Manifest icons: split "any" (circular, transparent) vs "maskable" (opaque safe-zone) ----
  for (const size of [192, 512]) {
    const anyBuf = await circularMask(size);
    fs.writeFileSync(path.join(PUBLIC_DIR, `icon-${size}.png`), anyBuf);
    console.log(`  [${++count}] public/icon-${size}.png (${size}x${size}, circular, purpose=any)`);

    const maskableBuf = await maskableSafeIcon(size);
    fs.writeFileSync(path.join(PUBLIC_DIR, `icon-${size}-maskable.png`), maskableBuf);
    console.log(`  [${++count}] public/icon-${size}-maskable.png (${size}x${size}, safe-zone, purpose=maskable)`);
  }

  for (const [size, svgName] of [[192, 'pwa-192x192.svg'], [512, 'pwa-512x512.svg']]) {
    const buf = fs.readFileSync(path.join(PUBLIC_DIR, `icon-${size}.png`));
    const svg = `<?xml version="1.0" encoding="UTF-8"?>
<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${size} ${size}" width="${size}" height="${size}">
  <image href="data:image/png;base64,${buf.toString('base64')}" width="${size}" height="${size}"/>
</svg>`;
    fs.writeFileSync(path.join(PUBLIC_DIR, svgName), svg);
    console.log(`  [${++count}] public/${svgName}`);
  }

  // ---- OG / social share image: SQUARE (1200x1200), full logo visible, never cropped ----
  const ogLogo = await circularMask(1080);
  await sharp({ create: { width: 1200, height: 1200, channels: 4, background: BRAND_GREEN } })
    .composite([{ input: ogLogo, gravity: 'center' }])
    .flatten({ background: '#006A4E' })
    .png()
    .toFile(path.join(PUBLIC_DIR, 'og-share-v3.png'));
  console.log(`  [${++count}] public/og-share-v3.png (1200x1200, square, uncropped)`);

  // Remove the old cropped 1200x630 duplicate + dead unused static manifest
  for (const stale of ['og-image.png', 'manifest.webmanifest']) {
    const p = path.join(PUBLIC_DIR, stale);
    if (fs.existsSync(p)) {
      fs.unlinkSync(p);
      console.log(`  [removed] public/${stale} (stale/superseded)`);
    }
  }

  // ---- icons/*.webp (used by legacy-nursery.html's "share app icon" button) ----
  if (fs.existsSync(ICONS_DIR)) {
    for (const size of [48, 72, 96, 128, 192, 256, 512]) {
      const buf = await circularMask(size);
      await sharp(buf).webp({ quality: 90 }).toFile(path.join(ICONS_DIR, `icon-${size}.webp`));
      console.log(`  [${++count}] icons/icon-${size}.webp (circular)`);
    }
  }

  console.log(`\n=== Done: ${count} files regenerated ===`);
}

main().catch((err) => {
  console.error('Fatal error:', err);
  process.exit(1);
});
